+     free((void *)value);
+     log_message(LOG_ERR, pamh, "Invalid STEP_SIZE option in \"%s\"",
+                 secret_filename);
+     return 0;
+   }
+   free((void *)value);
+ 
+   return get_time()/step;
+ }
